//# A Reliable and Generic Binary Multiplexer (Behavioural Implementation)

// But first, some background on the problems with multiplexers...

//## Simulation and Synthesis Mismatch

// A pitfall in the Verilog language is the treatment of unknown X values in
// `if` statements, and it can cause a mismatch between the simulated and the
// synthesized behaviours. I have observed this exact mismatch in the field.
// This problem carries over into the design of multiplexers in general.
// Here's a contrived example, where we select one of two possibilities:

//     reg                         selector;
//     reg     [WORD_WIDTH-1:0]    option_A;
//     reg     [WORD_WIDTH-1:0]    option_B;
//     reg     [WORD_WIDTH-1:0]    result;
//     
//     always @(*) begin
//         if (selector == 1'b0) begin
//             result = option_A;
//         end
//         else begin
//             result = option_B;
//         end
//     end

// The problem here happens if `selector` is X or Z-valued. In real hardware,
// we would expect an X or Z `selector` to cause `result` to obtain an
// X value, *but the `if` statement treats X as false, and so falls through to
// the `else` case*. The simulation returns `option_B` while the synthesis
// returns `X`. This difference can also confuse verification efforts, because
// it can show a failure in simulation where there isn't one.

// Instead of `if` statements, we can use the ternary `?:` operator, which
// behaves as expected. Except in cases where both `option_A/option_B`
// evaluate to 1 or 0, an X or Z-valued `selector` will return an X value:

//     always @(*) begin
//         result = (selector == 1'b0) ? option_A : option_B;
//     end

//## Inflexible Implementations

// However, [the ternary operator gets impractical for more that two
// options](./verilog.html#ternary), and the `case` statement gets tedious and
// error-prone as the number of cases increases. And both are too rigid,
// requiring changes to the multiplexer implementation should the number of
// inputs change.

//## A Generic Solution

// Instead of implementing multiple multiplexers of specific sizes, we can
// replace them all with a single multiplexer module, implemented using
// a vector part select, which simulates and synthesizes correctly, and
// accepts a parameterized number of inputs.  In the following code, we can
// think of `selector` as "addressing" one of the `words_in` options.

// Rather than change the number of input ports at each design change, pass
// a concatenation of words to `words_in` with the zeroth element on the
// right. The `selector` then selects one of the input words. If the
// `selector` value is greater than the number of input words, the output is
// unknown (depends on synthesized logic). If the `selector` is X or Z, the
// output is X or Z.

// This multiplexer can also cleanly express little bits of arbitrary logic:
// set the inputs to the possible output values (constant or otherwise) of
// your function, and let the `selector` input get decoded to one of those
// values.

`default_nettype none

module Multiplexer_Binary_Behavioural
#(
    parameter       WORD_WIDTH          = 0,
    parameter       ADDR_WIDTH          = 0,
    parameter       INPUT_COUNT         = 0,

    // Do not set at instantiation
    parameter   TOTAL_WIDTH = WORD_WIDTH * INPUT_COUNT
)
(
    input   wire    [ADDR_WIDTH-1:0]    selector,
    input   wire    [TOTAL_WIDTH-1:0]   words_in,
    output  reg     [WORD_WIDTH-1:0]    word_out
);

    initial begin
        word_out = {WORD_WIDTH{1'b0}};
    end

    always @(*) begin
        word_out = words_in[(selector * WORD_WIDTH) +: WORD_WIDTH];
    end

endmodule

//## Portability

// There's one problem here: if your HDL of choice does not have an analog of
// Verilog's vector part select, this design can't be translated. Thus, there
// exists [another, more structural implementation, which can be ported to
// other HDLs](./Multiplexer_Binary_Structural.html), and also expands the output
// function beyond the implicit Boolean OR found here.

//# Multiplexer (One-Hot)

// Takes in a one-hot bit vector (`selector`), and outputs the value of the
// corresponding input. All selectors and inputs are concatenated into
// a single vector each.

// If more than one `selector` bit is set, the output is a Boolean combination
// of the selected input words, as specified by `OPERATION`: OR for a plain
// multiplexer, AND to show each bit where all the words agree, NOR to show each
// bit which are not set in all the words, etc...

// The `IMPLEMENTATION` parameter defaults to "AND" since this is all Boolean
// logic, though if you are feeding the input words from registers all sharing
// common control logic, you might get a possibly better result by selecting
// "MUX". If it matters for speed or area, use the implementation which ends
// up using the register's reset/clear pin, which will remove the Annuller
// logic from the multiplexer itself.

`default_nettype none

module Multiplexer_One_Hot
#(
    parameter       WORD_WIDTH          = 0,
    parameter       WORD_COUNT          = 0,
    parameter       OPERATION           = "OR",
    parameter       IMPLEMENTATION      = "AND",

    // Do not set at instantiation
    parameter   TOTAL_WIDTH = WORD_COUNT * WORD_WIDTH
)
(
    input   wire    [WORD_COUNT-1:0]    selectors,
    input   wire    [TOTAL_WIDTH-1:0]   words_in,
    output  wire    [WORD_WIDTH-1:0]    word_out
);

// First, create a copy of `words_in`, but with non-selected words annulled.

    wire [TOTAL_WIDTH-1:0] words_in_selected;

    generate

        genvar i;

        for (i=0; i < WORD_COUNT; i=i+1) begin : per_word

            Annuller
            #(
                .WORD_WIDTH     (WORD_WIDTH),
                .IMPLEMENTATION (IMPLEMENTATION)
            )
            select_input
            (
                .annul       (selectors[i] == 1'b0),
                .data_in     (words_in          [WORD_WIDTH*i +: WORD_WIDTH]),
                .data_out    (words_in_selected [WORD_WIDTH*i +: WORD_WIDTH])
            );

        end

    endgenerate

// Then reduce the filtered words to one word, maybe getting a final useful
// computation done in the process, depending on the selected `OPERATION`.

    Word_Reducer
    #(
        .OPERATION  (OPERATION),
        .WORD_WIDTH (WORD_WIDTH),
        .WORD_COUNT (WORD_COUNT)
    )
    combine_words
    (
        .words_in   (words_in_selected),
        .word_out   (word_out)
    );

endmodule

//# Binary Demultiplexer

// Connects the `word_in` input port to one of the words in the `words_out`
// output port, as selected by the `selector` binary address, and raises the
// corresponding valid bit in the `valids_out` output port.  *If the
// `selector` value is greater than the number of output words specified by
// the `OUTPUT_COUNT` parameter, then none of the `valids_out` bits will be
// set.*

//## Implementation Options

// Set the `BROADCAST` parameter to 1 to simply replicate and connect
// `word_in` to each word in `words_out`, without any logic. The valid bit
// will indicate which downstream logic should accept the data, and other
// logic can snoop the data if that's part of your larger design.

// Set the `BROADCAST` parameter to 0 to send `word_in` to *only* the selected
// word in `words_out`, whose valid bit is set. All other output words are
// annulled to zero. If no valid bit is set, all output words stay at zero.

// Not broadcasting the input to the output costs some logic, but less than it
// appears from a standalone synthesis of the demultiplexer: the inferred
// [Annullers](./Annuller.html) will very likely disappear into downstream LUT
// logic, it also makes tracing a simulation easier, and adds some design
// security and robustness since unselected downstream logic cannot snoop or
// accidentally receive other data.

// If necessary, select the Annuller `IMPLEMENTATION` which yields the best
// logic synthesis. Usually, this does not matter, and can be set to "AND".

// Setting `BROADCAST` to any value other than 1 or 0 will disconnect
// `word_in` from `words_out`, raise some critical warnings in your CAD tool,
// and generally cause a lot of downstream logic to optimize away, so you
// should notice...

`default_nettype none

module Demultiplexer_Binary
#(
    parameter       BROADCAST           = 0,
    parameter       WORD_WIDTH          = 0,
    parameter       ADDR_WIDTH          = 0,
    parameter       OUTPUT_COUNT        = 0,
    parameter       IMPLEMENTATION      = "AND",

    // Do not set at instantiation
    parameter   TOTAL_WIDTH = WORD_WIDTH * OUTPUT_COUNT
)
(
    input   wire    [ADDR_WIDTH-1:0]    selector,
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  wire    [TOTAL_WIDTH-1:0]   words_out,
    output  wire    [OUTPUT_COUNT-1:0]  valids_out
);

// Convert the binary `selector` to a single one-hot bit vector
// which signals which output port will receive the input word.

    wire [OUTPUT_COUNT-1:0] selector_one_hot;

    Binary_to_One_Hot
    #(
        .BINARY_WIDTH   (ADDR_WIDTH),
        .OUTPUT_WIDTH   (OUTPUT_COUNT)
    )
    valid_out
    (
        .binary_in      (selector),
        .one_hot_out    (selector_one_hot)
    );

// Then use that one-hot selector to steer the input to a particular output.

    Demultiplexer_One_Hot
    #(
        .BROADCAST      (BROADCAST),
        .WORD_WIDTH     (WORD_WIDTH),
        .OUTPUT_COUNT   (OUTPUT_COUNT),
        .IMPLEMENTATION (IMPLEMENTATION)
    )
    word_in_demux
    (
        .selectors      (selector_one_hot),
        .word_in        (word_in),
        .words_out      (words_out),
        .valids_out     (valids_out)
    );

endmodule

//# Address Decoder (Static)

// A flexible address decoder. Works for any address range at any starting
// point. The base and bound addresses are set as parameters, so the range is
// fixed. This decoder works by checking if the input address lies between the
// base and bound (inclusive) of a range by comparing against each possible
// address within the range, then outputs the OR-reduction of all these
// checks.

// But there are a couple of caveats: your CAD tool will have to create
// a little netlist for up to all 2^ADDR_WIDTH possible addresses, and store
// the matches into a vector of up to 2^ADDR_WIDTH bits long, depending on the
// base and bound addresses.  Elaborating and optimizing this logic can take
// a *very* long time and, as I understand it, Verilog implementations have
// a maximum vector width of a million or so, so this decoder will be likley
// unusable for address ranges more than 20 bits wide.

// Also, even if your CAD tool can handle wider vectors, because we use an
// integer as counter, this decoder cannot be guaranteed to work for address
// ranges exceeding 32 bits, depending on your Verilog implementation.

// **I do not recommend this implementation.** I include it because I have put
// it to good use inside a CPU for decoding register operands, and it might be
// a good choice for very small, fixed address ranges if your CAD tool cannot
// fully optimize the [Behavioural Address
// Decoder](./Address_Decoder_Behavioural.html).

`default_nettype none

module Address_Decoder_Static
#(
    parameter       ADDR_WIDTH          = 0,
    parameter       ADDR_BASE           = 0,
    parameter       ADDR_BOUND          = 0
)
(
    input   wire    [ADDR_WIDTH-1:0]    addr,
    output  reg                         hit
);

    localparam ADDR_COUNT = ADDR_BOUND - ADDR_BASE + 1;
    localparam COUNT_ZERO = {ADDR_COUNT{1'b0}};

    initial begin
        hit = 1'b0;
    end

    integer                     i;
    reg     [ADDR_COUNT-1:0]    per_addr_match = COUNT_ZERO;

// Check each address in base/bound range for match, and store it in a vector
// for later OR-reduction.  Note that we select only the bit range we need
// from the index `i` so it doesn't raise a width mismatch warning when
// compared to the input address.  This does mean problems if `ADDR_WIDTH` is
// greater than 32 bits.

    always @(*) begin
        for(i = ADDR_BASE; i <= ADDR_BOUND; i = i + 1) begin : addr_decode
            per_addr_match[i-ADDR_BASE] = (addr == i[ADDR_WIDTH-1:0]);
        end
    end

    always @(*) begin : is_hit
        hit = |per_addr_match;
    end 

endmodule

//# Binary To One-Hot Converter

// Generates an output bit vector of up to 2^N bits with one bit set
// representing the N-bit input binary value.

// The width of the output vector is limited by the Verilog implementation to
// about a million bits, which means a maximum input binary width of 20 bits.
// Also, for very large output vectors, the synthesis can take a very long
// time. But in practice, you will never get near these limits.

// The output vector width may be more or less than all possible binary values.
// If the binary value does not map to any of the output bits, the output vector
// stays at zero, meaning "no value".

// This module is of great use when translating an "address" into a number of
// enable signals to select or filter something, such as a portable
// [multiplexer](Multiplexer_Binary_Structural.html).

`default_nettype none

module Binary_to_One_Hot
#(
    parameter       BINARY_WIDTH        = 0,
    parameter       OUTPUT_WIDTH        = 0 
)
(
    input   wire    [BINARY_WIDTH-1:0]  binary_in,
    output  wire    [OUTPUT_WIDTH-1:0]  one_hot_out
);

// Instantiate an address decoder for each possible *output* value.
// This way, binary input values outside of the output range
// result in a zero output.

    generate
        genvar i;
        for (i=0; i < OUTPUT_WIDTH; i=i+1) begin : per_output
            Address_Decoder_Behavioural
            #(
                .ADDR_WIDTH (BINARY_WIDTH)
            )
            one_hot_bit
            (
                .base_addr  (i[BINARY_WIDTH-1:0]),
                .bound_addr (i[BINARY_WIDTH-1:0]),
                .addr       (binary_in),
                .hit        (one_hot_out[i])
            );
        end
    endgenerate

endmodule

//# One-Hot Demultiplexer

// Connects the `word_in` input port to one of the words in the `words_out`
// output port, as selected by the `selectors` one-hot vector, and raises the
// corresponding valid bit in the `valids_out` output port.  *If more than one
// bit is set in the `selectors` input, then all the corresponding output
// words will get the input word value.*

//## Implementation Options

// Set the `BROADCAST` parameter to 1 to simply replicate and connect
// `word_in` to each word in `words_out`, without any logic. The valid bit
// will indicate which downstream logic should accept the data, and other
// logic can snoop the data if that's part of your larger design.

// Set the `BROADCAST` parameter to 0 to send `word_in` to *only* the selected
// word in `words_out`, whose valid bit is set. All other output words are
// annulled to zero. If no valid bit is set, all output words stay at zero.

// Not broadcasting the input to the output costs some logic, but less than it
// appears from a standalone synthesis of the demultiplexer: the inferred
// [Annullers](./Annuller.html) will very likely disappear into downstream LUT
// logic, it also makes tracing a simulation easier, and adds some design
// security and robustness since unselected downstream logic cannot snoop or
// accidentally receive other data.

// If necessary, select the Annuller `IMPLEMENTATION` which yields the best
// logic synthesis. Usually, this does not matter, and can be set to "AND".

// Setting `BROADCAST` to any value other than 1 or 0 will disconnect
// `word_in` from `words_out`, raise some critical warnings in your CAD tool,
// and generally cause a lot of downstream logic to optimize away, so you
// should notice...

`default_nettype none

module Demultiplexer_One_Hot
#(
    parameter       BROADCAST           = 0,
    parameter       WORD_WIDTH          = 0,
    parameter       OUTPUT_COUNT        = 0,
    parameter       IMPLEMENTATION      = "AND",

    // Do not set at instantiation
    parameter   TOTAL_WIDTH = WORD_WIDTH * OUTPUT_COUNT
)
(
    input   wire    [OUTPUT_COUNT-1:0]  selectors,
    input   wire    [WORD_WIDTH-1:0]    word_in,
    output  reg     [TOTAL_WIDTH-1:0]   words_out,
    output  reg     [OUTPUT_COUNT-1:0]  valids_out
);

    localparam OUTPUT_ZERO = {OUTPUT_COUNT{1'b0}};
    localparam TOTAL_ZERO  = {TOTAL_WIDTH{1'b0}};

    initial begin
        words_out  = TOTAL_ZERO;
        valids_out = OUTPUT_ZERO;
    end

// Pass along the selector to the downstream logic, so we know which output
// word is the selected one.

    always @(*) begin
        valids_out = selectors;
    end

// If we are *not* broadcasting, then for each output word, annul the output
// if its selector bit is not set.  Thus, only the selected output word will
// have the `word_in` data. All others will stay at zero.  Otherwise, simply
// replicate and connect the input to all outputs. 

    generate
        if (BROADCAST == 0) begin : gen_no_broadcast
            wire [TOTAL_WIDTH-1:0] words_out_internal;

            genvar i;
            for (i=0; i < OUTPUT_COUNT; i=i+1) begin: per_output
                Annuller
                #(
                    .WORD_WIDTH     (WORD_WIDTH),
                    .IMPLEMENTATION (IMPLEMENTATION)
                )
                output_gate
                (
                    .annul          (selectors[i] == 1'b0),
                    .data_in        (word_in),
                    .data_out       (words_out_internal[WORD_WIDTH*i +: WORD_WIDTH])
                );
            end

            always @(*) begin
                words_out = words_out_internal;
            end
        end
        else
        if (BROADCAST == 1) begin : gen_broadcast
            always @(*) begin
                words_out = {OUTPUT_COUNT{word_in}};
            end
        end
    endgenerate

endmodule

//# Address Decoder (Behavioural)

// A programmable address decoder. Works for any address range at any starting
// point, *and the base and bound addresses can be changed at runtime*.  We
// express this behaviourally with two unsigned integer comparisons to check
// if the address lies between the base and bound of a range, inclusively.

// This decoder scales to larger address ranges (20 bits or more) without
// hitting any Verilog implementation vector width limits or requiring long
// optimization of enormous netlists, as with the [Static Address
// Decoder](./Address_Decoder_Static.html).

// How this circuit synthesizes depends on your CAD tool. In the past, I saw
// this code synthesize to the expected arithmetic comparisons via
// subtraction, but a more recent version of the same CAD tool synthesizes to
// log<sub>2</sub>(ADDR_WIDTH) levels of LUT logic. *But it is unclear if that
// will be faster than arithmetic circuitry.* And of course, if you make the
// base and bound addresses constant, the logic will optimize further towards
// its minimal form.

// The base, bound, and input addresses all use the same width, which avoids
// the need for selecting parts of vectors and makes the enclosing code
// cleaner and more general.

// **This is the implementation I recommend for general use.** You can force
// a non-arithmetic implementation (but with a fixed range) by using the
// Static Address Decoder, or conversely, you can force an arithmetic
// implementation by using the [Arithmetic Address
// Decoder](./Address_Decoder_Arithmetic.html).

`default_nettype none

module Address_Decoder_Behavioural
#(
    parameter       ADDR_WIDTH          = 0
)
(
    input   wire    [ADDR_WIDTH-1:0]    base_addr,
    input   wire    [ADDR_WIDTH-1:0]    bound_addr,
    input   wire    [ADDR_WIDTH-1:0]    addr,
    output  reg                         hit
);

    initial begin
        hit = 1'b0;
    end

    reg base_or_higher = 1'b0;
    reg bound_or_lower = 1'b0;

    always @(*) begin
        base_or_higher = (addr >= base_addr);
        bound_or_lower = (addr <= bound_addr);
        hit            = (base_or_higher == 1'b1) && (bound_or_lower == 1'b1);
    end

endmodule

//# Address Translator (Static)

// *This is the fixed-range version of the [Arithmetic Address
// Translator](./Address_Translator_Arithmetic.html).*

// Translates a *fixed*, arbitrary, unaligned range of N locations into an
// aligned range (starting at zero, up to N-1) so the translated address can
// be used to sequentially index into other addressed components
// (multiplexers, address decoders, RAMs, etc...).

// When memory-mapping a small memory or a number of control registers to
// a base address that isn't a power-of-2, the Least Significant Bits (LSBs)
// which vary over the address range will not address the mapped entries in
// order. This addressing offset scrambles the order of the control registers
// and of the memory locations so that the mapped order no longer matches the
// physical order of the actual hardware, which makes design and debugging
// harder.

// If the address range does not start at a power-of-2 boundary, the LSBs will
// not count in strictly increasing order and will not start at zero: the
// order of the numbers the LSBs represent is rotated by the offset to the
// nearest power-of-2 boundary. Also, if the address range does not span
// a power-of-2 sized block, then not all possible LSB values will be present.

// However, we can describe a translation table as a small asynchronous
// read-only memory which translates only the raw LSBs into consecutive LSBs
// to then directly address the memory or control registers. A separate
// [Address Decoder](./Address_Decoder_Behavioural.html) signals when the
// translation is valid.

// For example, take 4 locations at addresses 7 to 10, which we would like to
// map to a range of 0 to 3. We want address 7 to access the zeroth location,
// and so on. To map 4 locations, the address' two LSBs must be translated as
// follows:

//<pre>
//01<b>11</b> (7)  --> 01<b>00</b> (4)
//10<b>00</b> (8)  --> 10<b>01</b> (5)
//10<b>01</b> (9)  --> 10<b>10</b> (6)
//10<b>10</b> (10) --> 10<b>11</b> (7)
//</pre>

// You can see the raw two LSBs are in the sequence 3,0,1,2, which we must map
// to 0,1,2,3. We can pre-fill a table with the right values to do that, where
// address 3 will contain value 0, address 0 will contain value 1, etc...
// Translating the LSBs like so re-aligns the addresses to the nearest
// power-of-2 boundary, leaving the LSBs in the order we need.

// Typically, you'll need this Address Translator alongside an Address Decoder
// module which decodes a *fixed* address range: either
// [Static](./Address_Decoder_Static.html), or
// [Behavioural](./Address_Decoder_Behavioural.html) or
// [Arithmetic](./Address_Decoder_Arithmetic.html) with constant base and
// bound addresses.

// Since we only translate the LSBs, the higher address bits are unused here,
// and would trigger CAD tool warnings about module inputs not driving
// anything.  Thus, we don't select the LSBs from the whole address here, and
// it is up to the enclosing module to feed the Address Translator only the
// necessary LSBs, which is fine since the enclosing module must already know
// the number of LSBs to translate. The output is the translated LSBs in
// consecutive order.

`default_nettype none

module Address_Translator_Static
#(
    parameter       INPUT_ADDR_BASE     = 0,
    parameter       OUTPUT_ADDR_WIDTH   = 0
)
(
    input   wire    [OUTPUT_ADDR_WIDTH-1:0] input_addr,
    output  reg     [OUTPUT_ADDR_WIDTH-1:0] output_addr
);

// Let's create the translation table and specify its implementation as LUT
// logic, otherwise it might end up as a Block RAM or asynchronous LUT RAM at
// random, and then the table cannot get optimized into other logic, and will
// likely be too slow. We make the table deep enough to hold all possible LSB
// values, which enables better logic optimization (no special cases for
// unused addresses).

    localparam OUTPUT_ADDR_DEPTH = 2**OUTPUT_ADDR_WIDTH;

    (* ramstyle = "logic" *)        // Quartus
    (* ram_style = "distributed" *) // Vivado
    reg [OUTPUT_ADDR_WIDTH-1:0] translation_table [OUTPUT_ADDR_DEPTH-1:0];

// Now lets construct the translation table entry index **j**. When
// initializing **j**, we must zero-pad the narrow input address up to the
// width of a Verilog integer, else the width mismatch raises warnings at its
// assigment. 

// We also need a simple loop counter **i** to iterate over the number of
// addresses to translate, which is the entire range described by the LSBs.

    integer i;
    integer j;
    localparam INTEGER_WIDTH    = 32;
    localparam PADSIZE          = INTEGER_WIDTH - OUTPUT_ADDR_WIDTH;
    localparam PADDING          = {PADSIZE{1'b0}};

// We then initialize **j** by slicing out the LSBs from the integer base
// address, and then padding it back to an integer. We then store the
// (strictly incrementing) corresponding LSBs from the **i** counter into each
// translation table entry indexed by **j**, wrapping around to the start of
// the table if necessary.

    initial begin
        j = {PADDING, INPUT_ADDR_BASE[OUTPUT_ADDR_WIDTH-1:0]};
        for(i = 0; i < OUTPUT_ADDR_DEPTH; i = i + 1) begin
            translation_table[j] = i[OUTPUT_ADDR_WIDTH-1:0];
            j = (j + 1) % OUTPUT_ADDR_DEPTH;
        end
    end

// Finally, after all these details, the translation itself is trivial.

    always @(*) begin
        output_addr = translation_table[input_addr];
    end

endmodule

//# Address Decoder (Arithmetic)

// A programmable address decoder. Works for any address range at any starting
// point, *and the base and bound addresses can be changed at runtime*.  We do
// this with two parallel subtractions [to calculate lesser/greater/equal
// predicates](./Arithmetic_Predicates_Binary.html) to check if the input
// address lies between the base and bound addresses, inclusively.

// This decoder scales to larger address ranges (20 bits or more) without
// hitting any Verilog implementation vector width limits or requiring long
// optimization of enormous netlists, as with the [static Address
// Decoder](./Address_Decoder_Static.html).

// For very small address ranges, this decoder will be larger (2 subtractors
// instead of a few LUTs). For very large address ranges (e.g. 32 bits or
// more), the speed of the arithmetic operations will become a limit, *but it
// is unclear if this will be slower than the log<sub>2</sub>(ADDR_WIDTH) deep
// tree of LUT logic* obtainable from a Behavioural Address Decoder.

// The base, bound, and input addresses all use the same width, which avoids
// the need for selecting parts of vectors and makes the enclosing code
// cleaner and more general.

// **Use this implementation if you must use arithmetic circuitry.**
// Otherwise, I recommend using the [Behavioural Address
// Decoder](./Address_Decoder_Behavioural.html).

`default_nettype none

module Address_Decoder_Arithmetic
#(
    parameter       ADDR_WIDTH          = 0
)
(
    input   wire    [ADDR_WIDTH-1:0]    base_addr,
    input   wire    [ADDR_WIDTH-1:0]    bound_addr,
    input   wire    [ADDR_WIDTH-1:0]    addr,
    output  reg                         hit
);

    initial begin
        hit = 1'b0;
    end

    wire base_or_higher;
    wire bound_or_lower;

    Arithmetic_Predicates_Binary
    #(
        .WORD_WIDTH         (ADDR_WIDTH)
    )
    lower_bound
    (
        .A                  (addr),
        .B                  (base_addr),

        // verilator lint_off PINCONNECTEMPTY
        .A_eq_B             (),

        .A_lt_B_unsigned    (),
        .A_lte_B_unsigned   (),
        .A_gt_B_unsigned    (),
        .A_gte_B_unsigned   (base_or_higher),

        .A_lt_B_signed      (),
        .A_lte_B_signed     (),
        .A_gt_B_signed      (),
        .A_gte_B_signed     ()
        // verilator lint_on PINCONNECTEMPTY
    );

    Arithmetic_Predicates_Binary
    #(
        .WORD_WIDTH         (ADDR_WIDTH)
    )
    upper_bound
    (
        .A                  (addr),
        .B                  (bound_addr),

        // verilator lint_off PINCONNECTEMPTY
        .A_eq_B             (),

        .A_lt_B_unsigned    (),
        .A_lte_B_unsigned   (bound_or_lower),
        .A_gt_B_unsigned    (),
        .A_gte_B_unsigned   (),

        .A_lt_B_signed      (),
        .A_lte_B_signed     (),
        .A_gt_B_signed      (),
        .A_gte_B_signed     ()
        // verilator lint_on PINCONNECTEMPTY
    );

    always @(*) begin
        hit  = (base_or_higher == 1'b1) && (bound_or_lower == 1'b1);
    end

endmodule
